@pytest.mark.asyncio
async def test_assess_application_unknown_product(client):
    response = await client.post(
        "/api/v1/assess/application",
        json={
            "product": "not_a_product",
            "declared": {
                "customer_name": "X",
                "amount": 1,
                "term_months": 12,
                "monthly_income": 1,
                "declared_purpose": "test",
            },
            "documents": [],
        },
