function Stop-PidSafe([int]$ProcessId, [string]$Name) {
    if ($ProcessId -le 0) { return }
    try {
        $proc = Get-Process -Id $ProcessId -ErrorAction SilentlyContinue
        if (-not $proc) { return }
        Stop-Process -Id $ProcessId -Force -ErrorAction SilentlyContinue
        # Kill child trees (uvicorn reloader / npm)
        Get-CimInstance Win32_Process -ErrorAction SilentlyContinue |
            Where-Object { $_.ParentProcessId -eq $ProcessId } |
            ForEach-Object { Stop-Process -Id $_.ProcessId -Force -ErrorAction SilentlyContinue }
        Write-Host "  stopped $Name (pid $ProcessId)" -ForegroundColor Yellow
    }
    catch {
        Write-Host "  skip $Name (pid $ProcessId): $_" -ForegroundColor DarkYellow
    }
}

function Start-LoggedProcess {
    param(
        [string]$Name,
        [string]$FilePath,
        [string[]]$ArgumentList,
        [string]$WorkingDirectory,
        [hashtable]$EnvVars = @{}
    )
    Ensure-RunDirs
    $outLog = Join-Path $LogDir "$Name.out.log"
    $errLog = Join-Path $LogDir "$Name.err.log"
    if (Test-Path $outLog) { Remove-Item $outLog -Force -ErrorAction SilentlyContinue }
    if (Test-Path $errLog) { Remove-Item $errLog -Force -ErrorAction SilentlyContinue }

    # Start-Process -Environment needs PS 7+; use cmd wrapper for env on WinPS 5.1
    $envPrefix = ""
    foreach ($key in $EnvVars.Keys) {
        $val = $EnvVars[$key]
        $envPrefix += "set `"$key=$val`" && "
    }
    $argStr = ($ArgumentList | ForEach-Object {
            if ($_ -match '\s') { '"{0}"' -f $_ } else { $_ }
        }) -join " "
    $cmdLine = "$envPrefix`"$FilePath`" $argStr"

    $proc = Start-Process -FilePath "cmd.exe" `
        -ArgumentList "/c", $cmdLine `
        -WorkingDirectory $WorkingDirectory `
        -RedirectStandardOutput $outLog `
        -RedirectStandardError $errLog `
        -WindowStyle Hidden `
        -PassThru

    Write-Host "  started $Name (pid $($proc.Id)) → .run\logs\$Name.*.log" -ForegroundColor Green
    return [int]$proc.Id
}

